const aFetch = async (path, body=null, method="POST", tk=null) => {
  try {
    const r = await fetch(SB_URL+path, { method, headers: {"Content-Type":"application/json","apikey":SB_KEY,...(tk&&{Authorization:`Bearer ${tk}`})}, ...(body!==null&&{body:JSON.stringify(body)}) });
    return { data: await r.json(), ok: r.ok };
  } catch { return { data:{error_description:"Sem conexao com o servidor."}, ok:false }; }
};
const SB = {
  signUp:      (e,p)   => aFetch("/auth/v1/signup",{email:e,password:p}),
  signIn:      (e,p)   => aFetch("/auth/v1/token?grant_type=password",{email:e,password:p}),
  sendOTP:     e       => aFetch("/auth/v1/otp",{email:e,options:{shouldCreateUser:false}}),
  verifyOTP:   (e,t)   => aFetch("/auth/v1/verify",{type:"email",email:e,token:t}),
  signOut:     tk      => aFetch("/auth/v1/logout",null,"POST",tk),
  updatePwd:   (tk,p)  => aFetch("/auth/v1/user",{password:p},"PUT",tk),
  refreshToken: rt     => aFetch("/auth/v1/token?grant_type=refresh_token",{refresh_token:rt}),
};

const uid = tk => { try { return JSON.parse(atob(tk.split(".")[1])).sub; } catch { return null; } };
const dFetch = async (path, method="GET", body=null, tk) => {
  try {
    const prefer = method==="POST"?"return=representation,resolution=merge-duplicates":"return=representation";
    const r = await fetch(`${SB_URL}/rest/v1/${path}`, { method, headers:{"apikey":SB_KEY,"Authorization":`Bearer ${tk}`,"Content-Type":"application/json","Prefer":prefer}, ...(body!==null&&{body:JSON.stringify(body)}) });
    if(r.status===204) return [];
    return await r.json();
  } catch { return null; }
};
