const trialInfo = p => {
  if(!p) return {daysLeft:7,hoursLeft:0,expired:false,paid:false};
  if(p.subscription_status==="active") return {daysLeft:0,hoursLeft:0,expired:false,paid:true};
  const ms=(new Date(p.trial_start).getTime()+7*864e5)-Date.now();
  return {daysLeft:Math.max(0,Math.floor(ms/864e5)),hoursLeft:Math.max(0,Math.floor((ms%864e5)/36e5)),expired:ms<=0,paid:false};
};

